import React from 'react';
import { Routes as RouteContainer, Route } from "react-router-dom";

import { Screens } from '../screens';

export const Routes = () => {
	return (
    <RouteContainer>
      <Route
        path="*"
        element={
          <RouteContainer>
            <Route path="/" element={<Screens.Home />} />
            <Route path="*" element={<Screens.PageNotFound />} />
          </RouteContainer>
        }
      />
    </RouteContainer>
  );
}
